#!/usr/bin/env bash
#
# bench-admission.sh — cold vs warm timing for the admission CLI surface.
#
# On this mesh the user explicitly wants BOTH numbers: page-cache / fresh-state
# vs warm-state make a big difference. This harness times the SHORT admission
# operations (no heavy fat-station inference here — that is the demo's Gate A
# job). For each op it reports the MEDIAN of a few runs, in milliseconds:
#
#   COLD : first invocation against a FRESH MONSTER_GUARD_HOME (no ledger,
#          no root.key, no agent secrets, no warm dyld/exec cache for that home).
#   WARM : repeated invocations against the SAME, already-initialized home.
#
# Ops timed:
#   - whoami                 (pure DID derivation; no admission roundtrip)
#   - spawn (oath-admitted)  (full admission roundtrip via monster-guard)
#   - delegate-spawn         (attenuated UCAN minting)
#   - audit --verify         (chain recompute; SKIPPED if the CLI is absent)
#   - reap --cascade         (3-node subtree closure; SKIPPED if absent)
#   - auto (1 tick)          (autonomic read+decide on a QUIET partyline -> HOLD;
#                             SKIPPED if the auto CLI is absent)
#
# It changes nothing outside its temp homes and reaps any sleep/guard procs it
# starts. No emojis. No git. No build.
#
# Usage:  bash scripts/bench-admission.sh
#         BENCH_RUNS=7 bash scripts/bench-admission.sh   # more samples

set -euo pipefail

# ---------------------------------------------------------------------------
# Resolve the gnosis tree and the release binaries (same layout as the demo).
# ---------------------------------------------------------------------------
script_dir="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
swarm_dir="$(cd "${script_dir}/.." && pwd)"
gnosis_dir="$(cd "${swarm_dir}/.." && pwd)"

GUARD_BIN="${gnosis_dir}/monster-guard/target/release/monster-guard"
RESIDENT_BIN="${gnosis_dir}/monster-resident/target/release/monster-resident"
SWARM_BIN="${gnosis_dir}/monster-swarm/target/release/monster-swarm"
DI_BIN_DIR="${gnosis_dir}/distributed-inference/target/release"

for pair in \
  "monster-guard:${GUARD_BIN}" \
  "monster-resident:${RESIDENT_BIN}" \
  "monster-swarm:${SWARM_BIN}"; do
  name="${pair%%:*}"; path="${pair#*:}"
  if [[ ! -x "${path}" ]]; then
    echo "error: ${name} release binary not found at:" >&2
    echo "       ${path}" >&2
    exit 1
  fi
done

export PATH="${DI_BIN_DIR}:${PATH}"

DEFAULT_OATH="${swarm_dir}/oaths/default.oath.json"
export MONSTER_GUARD_BIN="${GUARD_BIN}"
export MONSTER_SWARM_NODES="/bin"

BENCH_RUNS="${BENCH_RUNS:-5}"     # samples per cell; median reported

# Track temp homes so cleanup can reap stragglers.
HOMES_FILE="$(mktemp "${TMPDIR:-/tmp}/bench-homes.XXXXXX")"

cleanup() {
  echo
  echo "cleanup: reaping any sleep / guard procs and temp homes..."
  pkill -f "${GUARD_BIN}" 2>/dev/null || true
  pkill -f "/bin/sleep 3600" 2>/dev/null || true
  pkill -f "/bin/sleep 1" 2>/dev/null || true
  if [[ -f "${HOMES_FILE}" ]]; then
    while IFS= read -r h; do
      [[ -n "${h}" && -d "${h}" ]] && rm -rf "${h}"
    done < "${HOMES_FILE}"
    rm -f "${HOMES_FILE}"
  fi
  echo "done."
}
trap cleanup EXIT INT TERM

# Wall clock in integer milliseconds (perl Time::HiRes is always on macOS).
now_ms() { perl -MTime::HiRes=time -e 'printf "%d\n", time()*1000'; }

# median of a whitespace/newline-separated list of integers.
median() {
  printf '%s\n' "$@" | sort -n | awk '
    { a[NR]=$1 }
    END {
      if (NR==0) { print "NA"; exit }
      if (NR%2==1) { print a[(NR+1)/2] }
      else { printf "%d\n", (a[NR/2] + a[NR/2+1]) / 2 }
    }'
}

# Make a fresh, registered temp home and echo its path (tracked for cleanup).
fresh_home() {
  local h
  h="$(mktemp -d "${TMPDIR:-/tmp}/bench-admission.XXXXXX")"
  printf '%s\n' "${h}" >> "${HOMES_FILE}"
  printf '%s' "${h}"
}

# Initialize a home so the FIRST admission op there does not pay setup costs we
# attribute to the op itself. (whoami/keygen materialize root.key + identity.)
warm_init_home() {
  local h="$1"
  MONSTER_GUARD_HOME="${h}" "${RESIDENT_BIN}" keygen >/dev/null 2>&1 || true
  MONSTER_GUARD_HOME="${h}" "${SWARM_BIN}" whoami >/dev/null 2>&1 || true
}

# Mint a fleet UCAN in a given home; echoes "DID<TAB>SECRET<TAB>UCAN".
mint_fleet() {
  local h="$1" kj did sec ucan
  kj="$(MONSTER_GUARD_HOME="${h}" "${RESIDENT_BIN}" keygen)"
  did="$(printf '%s' "${kj}" | sed -n 's/.*"did"[[:space:]]*:[[:space:]]*"\([^"]*\)".*/\1/p')"
  sec="$(printf '%s' "${kj}" | sed -n 's/.*"secret"[[:space:]]*:[[:space:]]*"\([^"]*\)".*/\1/p')"
  ucan="$(MONSTER_GUARD_HOME="${h}" "${RESIDENT_BIN}" grant --audience "${did}" --with agent:fleet --can 'agent/*')"
  printf '%s\t%s\t%s' "${did}" "${sec}" "${ucan}"
}

# Detect whether the audit subcommand exists (it may be sibling-pending).
# Capture to a variable first: piping straight into `grep -q` lets grep close
# the pipe early, which SIGPIPEs the swarm binary and (under pipefail) flips the
# pipeline status, mis-detecting the CLI as present. Same idiom as the demo.
AUDIT_PRESENT=0
audit_probe="$("${SWARM_BIN}" audit --verify --json 2>&1 || true)"
if ! printf '%s' "${audit_probe}" | grep -qi 'unknown subcommand'; then
  AUDIT_PRESENT=1
fi

# Detect whether `reap --cascade` exists (sibling-pending lineage cascade). Same
# capture-then-grep idiom: a straight pipe into grep -q SIGPIPEs the binary and
# (under pipefail) flips the status, mis-detecting the flag. Combined streams so
# we catch clap's "unexpected argument" / "unknown subcommand" on either stream.
CASCADE_PRESENT=0
cascade_probe="$("${SWARM_BIN}" reap --cascade --ucan x --id __cascade_probe__ --json 2>&1 || true)"
if ! printf '%s' "${cascade_probe}" | grep -Eqi 'unexpected argument|unknown subcommand|unrecognized'; then
  CASCADE_PRESENT=1
fi

# Detect whether the autonomic loop subcommand `auto` exists. Same capture-then-
# grep idiom: run it with no args (it prints "--ucan required", NOT "unknown
# subcommand", when present) and check the banner.
AUTO_PRESENT=0
auto_probe="$("${SWARM_BIN}" auto 2>&1 || true)"
if ! printf '%s' "${auto_probe}" | grep -Eqi 'unknown subcommand|unrecognized'; then
  AUTO_PRESENT=1
fi

echo "monster-swarm admission benchmark (cold vs warm)"
echo "machine: local CPU, $(uname -s) $(uname -m)"
echo "runs per cell (median): ${BENCH_RUNS}"
echo "node allowlist: ${MONSTER_SWARM_NODES} (treating /bin/sleep as a node)"
[[ "${AUDIT_PRESENT}" -eq 1 ]] && echo "audit CLI: present" || echo "audit CLI: ABSENT (audit --verify rows skipped)"
[[ "${CASCADE_PRESENT}" -eq 1 ]] && echo "cascade CLI: present" || echo "cascade CLI: ABSENT (reap --cascade row skipped)"
[[ "${AUTO_PRESENT}" -eq 1 ]] && echo "auto CLI: present" || echo "auto CLI: ABSENT (auto (1 tick) row skipped)"
echo

# ---------------------------------------------------------------------------
# 1) whoami — COLD: fresh home each run; WARM: same warm home each run.
# ---------------------------------------------------------------------------
whoami_cold=(); whoami_warm=()
for ((i=0; i<BENCH_RUNS; i++)); do
  h="$(fresh_home)"
  t0="$(now_ms)"; MONSTER_GUARD_HOME="${h}" "${SWARM_BIN}" whoami >/dev/null 2>&1 || true; t1="$(now_ms)"
  whoami_cold+=( $((t1 - t0)) )
done
hw="$(fresh_home)"; warm_init_home "${hw}"
for ((i=0; i<BENCH_RUNS; i++)); do
  t0="$(now_ms)"; MONSTER_GUARD_HOME="${hw}" "${SWARM_BIN}" whoami >/dev/null 2>&1 || true; t1="$(now_ms)"
  whoami_warm+=( $((t1 - t0)) )
done

# ---------------------------------------------------------------------------
# 2) spawn (oath-admitted) — full admission roundtrip through monster-guard.
#    COLD: fresh home + fresh fleet UCAN each run. WARM: same home + UCAN.
# ---------------------------------------------------------------------------
spawn_cold=(); spawn_warm=()
for ((i=0; i<BENCH_RUNS; i++)); do
  h="$(fresh_home)"
  IFS=$'\t' read -r did sec ucan <<<"$(mint_fleet "${h}")"
  t0="$(now_ms)"
  MONSTER_GUARD_HOME="${h}" "${SWARM_BIN}" spawn --ucan "${ucan}" --node sleep \
    --id bench-spawn-cold-${i} --caps net --lease 1 --grant-ttl 60 \
    --oath "${DEFAULT_OATH}" -- 1 >/dev/null 2>&1 || true
  t1="$(now_ms)"
  spawn_cold+=( $((t1 - t0)) )
  MONSTER_GUARD_HOME="${h}" "${SWARM_BIN}" reap --ucan "${ucan}" --id bench-spawn-cold-${i} >/dev/null 2>&1 || true
done
hw="$(fresh_home)"; warm_init_home "${hw}"
IFS=$'\t' read -r wdid wsec wucan <<<"$(mint_fleet "${hw}")"
# Prime the spawn path once so dyld/guard exec is warm before we measure.
MONSTER_GUARD_HOME="${hw}" "${SWARM_BIN}" spawn --ucan "${wucan}" --node sleep \
  --id bench-spawn-prime --caps net --lease 1 --grant-ttl 60 --oath "${DEFAULT_OATH}" -- 1 >/dev/null 2>&1 || true
MONSTER_GUARD_HOME="${hw}" "${SWARM_BIN}" reap --ucan "${wucan}" --id bench-spawn-prime >/dev/null 2>&1 || true
for ((i=0; i<BENCH_RUNS; i++)); do
  t0="$(now_ms)"
  MONSTER_GUARD_HOME="${hw}" "${SWARM_BIN}" spawn --ucan "${wucan}" --node sleep \
    --id bench-spawn-warm-${i} --caps net --lease 1 --grant-ttl 60 \
    --oath "${DEFAULT_OATH}" -- 1 >/dev/null 2>&1 || true
  t1="$(now_ms)"
  spawn_warm+=( $((t1 - t0)) )
  MONSTER_GUARD_HOME="${hw}" "${SWARM_BIN}" reap --ucan "${wucan}" --id bench-spawn-warm-${i} >/dev/null 2>&1 || true
done

# ---------------------------------------------------------------------------
# 3) delegate-spawn — attenuated UCAN minting (no node launched).
#    Token capture is stdout ONLY (status line goes to stderr).
# ---------------------------------------------------------------------------
deleg_cold=(); deleg_warm=()
for ((i=0; i<BENCH_RUNS; i++)); do
  h="$(fresh_home)"
  IFS=$'\t' read -r did sec ucan <<<"$(mint_fleet "${h}")"
  ckj="$(MONSTER_GUARD_HOME="${h}" "${RESIDENT_BIN}" keygen)"
  cdid="$(printf '%s' "${ckj}" | sed -n 's/.*"did"[[:space:]]*:[[:space:]]*"\([^"]*\)".*/\1/p')"
  t0="$(now_ms)"
  MONSTER_GUARD_HOME="${h}" "${SWARM_BIN}" delegate-spawn --ucan "${ucan}" \
    --issuer-secret "${sec}" --to "${cdid}" --caps net --ttl 60 >/dev/null 2>/dev/null || true
  t1="$(now_ms)"
  deleg_cold+=( $((t1 - t0)) )
done
hw="$(fresh_home)"; warm_init_home "${hw}"
IFS=$'\t' read -r wdid wsec wucan <<<"$(mint_fleet "${hw}")"
wckj="$(MONSTER_GUARD_HOME="${hw}" "${RESIDENT_BIN}" keygen)"
wcdid="$(printf '%s' "${wckj}" | sed -n 's/.*"did"[[:space:]]*:[[:space:]]*"\([^"]*\)".*/\1/p')"
MONSTER_GUARD_HOME="${hw}" "${SWARM_BIN}" delegate-spawn --ucan "${wucan}" \
  --issuer-secret "${wsec}" --to "${wcdid}" --caps net --ttl 60 >/dev/null 2>/dev/null || true
for ((i=0; i<BENCH_RUNS; i++)); do
  t0="$(now_ms)"
  MONSTER_GUARD_HOME="${hw}" "${SWARM_BIN}" delegate-spawn --ucan "${wucan}" \
    --issuer-secret "${wsec}" --to "${wcdid}" --caps net --ttl 60 >/dev/null 2>/dev/null || true
  t1="$(now_ms)"
  deleg_warm+=( $((t1 - t0)) )
done

# ---------------------------------------------------------------------------
# 4) audit --verify — chain recompute (guarded; skipped if CLI absent).
# ---------------------------------------------------------------------------
audit_cold=(); audit_warm=()
if [[ "${AUDIT_PRESENT}" -eq 1 ]]; then
  for ((i=0; i<BENCH_RUNS; i++)); do
    h="$(fresh_home)"
    IFS=$'\t' read -r did sec ucan <<<"$(mint_fleet "${h}")"
    # Generate a few lifecycle events so the chain is non-trivial to verify.
    MONSTER_GUARD_HOME="${h}" "${SWARM_BIN}" spawn --ucan "${ucan}" --node sleep \
      --id bench-audit-cold-${i} --caps net --lease 1 --grant-ttl 60 --oath "${DEFAULT_OATH}" -- 1 >/dev/null 2>&1 || true
    MONSTER_GUARD_HOME="${h}" "${SWARM_BIN}" reap --ucan "${ucan}" --id bench-audit-cold-${i} >/dev/null 2>&1 || true
    t0="$(now_ms)"
    MONSTER_GUARD_HOME="${h}" "${SWARM_BIN}" audit --verify --json >/dev/null 2>&1 || true
    t1="$(now_ms)"
    audit_cold+=( $((t1 - t0)) )
  done
  hw="$(fresh_home)"; warm_init_home "${hw}"
  IFS=$'\t' read -r wdid wsec wucan <<<"$(mint_fleet "${hw}")"
  MONSTER_GUARD_HOME="${hw}" "${SWARM_BIN}" spawn --ucan "${wucan}" --node sleep \
    --id bench-audit-warm --caps net --lease 1 --grant-ttl 60 --oath "${DEFAULT_OATH}" -- 1 >/dev/null 2>&1 || true
  MONSTER_GUARD_HOME="${hw}" "${SWARM_BIN}" reap --ucan "${wucan}" --id bench-audit-warm >/dev/null 2>&1 || true
  MONSTER_GUARD_HOME="${hw}" "${SWARM_BIN}" audit --verify --json >/dev/null 2>&1 || true   # prime
  for ((i=0; i<BENCH_RUNS; i++)); do
    t0="$(now_ms)"
    MONSTER_GUARD_HOME="${hw}" "${SWARM_BIN}" audit --verify --json >/dev/null 2>&1 || true
    t1="$(now_ms)"
    audit_warm+=( $((t1 - t0)) )
  done
fi

# ---------------------------------------------------------------------------
# 5) reap --cascade — lineage-aware cascade revocation of a small (3-node)
#    subtree: parent -> child -> grandchild. We time ONLY the cascade reap; the
#    subtree must be rebuilt before each timed run because the reap is
#    destructive. COLD: fresh home + fresh subtree each run. WARM: same warm
#    home (warm dyld/exec/identity), fresh subtree per run. Guarded: skipped if
#    the cascade CLI is absent. No heavy fat-station inference here.
# ---------------------------------------------------------------------------

# Build a 3-node lineage (parent -> child -> grandchild) in home $1 under fleet
# UCAN $2 / secret $3, with the id suffix $4. Uses the demo's delegate-spawn ->
# spawn pattern so each agent's spawned_by chains to its parent agent's DID:
# spawn sets spawned_by = the UCAN HOLDER (chain-tip audience). The deeper
# (grandchild) delegation is ISSUED by the parent agent, signed with its on-disk
# secret (agents/<id>.key, hex as text). Token capture is stdout ONLY (the
# delegate-spawn status line is on stderr).
build_subtree() {
  local h="$1" ucan="$2" sec="$3" sfx="$4"
  local pj pdid clin cj cdid psec glin
  MONSTER_GUARD_HOME="${h}" "${SWARM_BIN}" spawn --ucan "${ucan}" --node sleep \
    --id "casc-parent-${sfx}" --caps net --lease 3600 --grant-ttl 3600 \
    --oath "${DEFAULT_OATH}" -- 3600 >/dev/null 2>&1 || true
  pj="$(MONSTER_GUARD_HOME="${h}" "${SWARM_BIN}" list --json 2>/dev/null | tr -d '\n' \
        | sed 's/},[[:space:]]*{/}\n{/g' | grep "\"id\"[[:space:]]*:[[:space:]]*\"casc-parent-${sfx}\"")"
  pdid="$(printf '%s' "${pj}" | sed -n 's/.*"did"[[:space:]]*:[[:space:]]*"\([^"]*\)".*/\1/p' | head -n 1)"
  clin="$(MONSTER_GUARD_HOME="${h}" "${SWARM_BIN}" delegate-spawn --ucan "${ucan}" \
        --issuer-secret "${sec}" --to "${pdid}" --caps net --ttl 3600 2>/dev/null || true)"
  MONSTER_GUARD_HOME="${h}" "${SWARM_BIN}" spawn --ucan "${clin}" --node sleep \
    --id "casc-child-${sfx}" --caps net --lease 3600 --grant-ttl 3600 -- 3600 >/dev/null 2>&1 || true
  cj="$(MONSTER_GUARD_HOME="${h}" "${SWARM_BIN}" list --json 2>/dev/null | tr -d '\n' \
        | sed 's/},[[:space:]]*{/}\n{/g' | grep "\"id\"[[:space:]]*:[[:space:]]*\"casc-child-${sfx}\"")"
  cdid="$(printf '%s' "${cj}" | sed -n 's/.*"did"[[:space:]]*:[[:space:]]*"\([^"]*\)".*/\1/p' | head -n 1)"
  # Deeper delegation is issued by the PARENT agent (clin's audience), signed
  # with the parent's on-disk secret, --to the CHILD agent's DID.
  psec=""; [[ -f "${h}/agents/casc-parent-${sfx}.key" ]] && psec="$(cat "${h}/agents/casc-parent-${sfx}.key")"
  glin="$(MONSTER_GUARD_HOME="${h}" "${SWARM_BIN}" delegate-spawn --ucan "${clin}" \
        --issuer-secret "${psec}" --to "${cdid}" --caps net --ttl 3600 2>/dev/null || true)"
  MONSTER_GUARD_HOME="${h}" "${SWARM_BIN}" spawn --ucan "${glin}" --node sleep \
    --id "casc-grandchild-${sfx}" --caps net --lease 3600 --grant-ttl 3600 -- 3600 >/dev/null 2>&1 || true
}

cascade_cold=(); cascade_warm=()
if [[ "${CASCADE_PRESENT}" -eq 1 ]]; then
  for ((i=0; i<BENCH_RUNS; i++)); do
    h="$(fresh_home)"
    IFS=$'\t' read -r did sec ucan <<<"$(mint_fleet "${h}")"
    build_subtree "${h}" "${ucan}" "${sec}" "c${i}"
    t0="$(now_ms)"
    MONSTER_GUARD_HOME="${h}" "${SWARM_BIN}" reap --cascade --ucan "${ucan}" \
      --id "casc-parent-c${i}" --json >/dev/null 2>&1 || true
    t1="$(now_ms)"
    cascade_cold+=( $((t1 - t0)) )
  done
  hw="$(fresh_home)"; warm_init_home "${hw}"
  IFS=$'\t' read -r wdid wsec wucan <<<"$(mint_fleet "${hw}")"
  # Prime: build + cascade once so dyld/guard exec is warm before measuring.
  build_subtree "${hw}" "${wucan}" "${wsec}" "prime"
  MONSTER_GUARD_HOME="${hw}" "${SWARM_BIN}" reap --cascade --ucan "${wucan}" \
    --id "casc-parent-prime" --json >/dev/null 2>&1 || true
  for ((i=0; i<BENCH_RUNS; i++)); do
    build_subtree "${hw}" "${wucan}" "${wsec}" "w${i}"
    t0="$(now_ms)"
    MONSTER_GUARD_HOME="${hw}" "${SWARM_BIN}" reap --cascade --ucan "${wucan}" \
      --id "casc-parent-w${i}" --json >/dev/null 2>&1 || true
    t1="$(now_ms)"
    cascade_warm+=( $((t1 - t0)) )
  done
fi

# ---------------------------------------------------------------------------
# 6) auto (1 tick) — the autonomic loop's per-tick READ + DECIDE overhead. We
#    time ONE `auto` tick against a QUIET partyline (no broadcaster running, so
#    the loop reads the collective consciousness, finds it within the homeostasis
#    band, and HOLDs — no bud, no reap). --dwell-ms 0 collapses the partyline
#    LISTEN window to zero so we measure only the read+decide cost, not the
#    sampling dwell. COLD: fresh home + fresh fleet UCAN each run (the queen is
#    seeded once per home so the floor is satisfiable). WARM: same warm home +
#    UCAN, primed once. Guarded: skipped if the auto CLI is absent.
# ---------------------------------------------------------------------------
auto_cold=(); auto_warm=()
if [[ "${AUTO_PRESENT}" -eq 1 ]]; then
  for ((i=0; i<BENCH_RUNS; i++)); do
    h="$(fresh_home)"
    IFS=$'\t' read -r did sec ucan <<<"$(mint_fleet "${h}")"
    # Seed a queen so --min-live is satisfiable; not part of the timed window.
    MONSTER_GUARD_HOME="${h}" "${SWARM_BIN}" spawn --ucan "${ucan}" --node sleep \
      --id bench-auto-queen-c${i} --caste breeder --caps net --lease 3600 \
      --grant-ttl 3600 -- 3600 >/dev/null 2>&1 || true
    t0="$(now_ms)"
    MONSTER_GUARD_HOME="${h}" "${SWARM_BIN}" auto --ucan "${ucan}" --node sleep \
      --bud-at 4 --reap-below 0 --min-live 1 --dwell-ms 0 >/dev/null 2>&1 || true
    t1="$(now_ms)"
    auto_cold+=( $((t1 - t0)) )
    MONSTER_GUARD_HOME="${h}" "${SWARM_BIN}" reap --ucan "${ucan}" --id bench-auto-queen-c${i} >/dev/null 2>&1 || true
  done
  hw="$(fresh_home)"; warm_init_home "${hw}"
  IFS=$'\t' read -r wdid wsec wucan <<<"$(mint_fleet "${hw}")"
  MONSTER_GUARD_HOME="${hw}" "${SWARM_BIN}" spawn --ucan "${wucan}" --node sleep \
    --id bench-auto-queen-w --caste breeder --caps net --lease 3600 \
    --grant-ttl 3600 -- 3600 >/dev/null 2>&1 || true
  # Prime the auto path once so dyld/guard exec is warm before we measure.
  MONSTER_GUARD_HOME="${hw}" "${SWARM_BIN}" auto --ucan "${wucan}" --node sleep \
    --bud-at 4 --reap-below 0 --min-live 1 --dwell-ms 0 >/dev/null 2>&1 || true
  for ((i=0; i<BENCH_RUNS; i++)); do
    t0="$(now_ms)"
    MONSTER_GUARD_HOME="${hw}" "${SWARM_BIN}" auto --ucan "${wucan}" --node sleep \
      --bud-at 4 --reap-below 0 --min-live 1 --dwell-ms 0 >/dev/null 2>&1 || true
    t1="$(now_ms)"
    auto_warm+=( $((t1 - t0)) )
  done
  MONSTER_GUARD_HOME="${hw}" "${SWARM_BIN}" reap --ucan "${wucan}" --id bench-auto-queen-w >/dev/null 2>&1 || true
fi

# ---------------------------------------------------------------------------
# Report.
# ---------------------------------------------------------------------------
m_whoami_cold="$(median "${whoami_cold[@]}")"; m_whoami_warm="$(median "${whoami_warm[@]}")"
m_spawn_cold="$(median "${spawn_cold[@]}")";   m_spawn_warm="$(median "${spawn_warm[@]}")"
m_deleg_cold="$(median "${deleg_cold[@]}")";   m_deleg_warm="$(median "${deleg_warm[@]}")"
if [[ "${AUDIT_PRESENT}" -eq 1 ]]; then
  m_audit_cold="$(median "${audit_cold[@]}")"; m_audit_warm="$(median "${audit_warm[@]}")"
else
  m_audit_cold="SKIP"; m_audit_warm="SKIP"
fi
if [[ "${CASCADE_PRESENT}" -eq 1 ]]; then
  m_cascade_cold="$(median "${cascade_cold[@]}")"; m_cascade_warm="$(median "${cascade_warm[@]}")"
else
  m_cascade_cold="SKIP"; m_cascade_warm="SKIP"
fi
if [[ "${AUTO_PRESENT}" -eq 1 ]]; then
  m_auto_cold="$(median "${auto_cold[@]}")"; m_auto_warm="$(median "${auto_warm[@]}")"
else
  m_auto_cold="SKIP"; m_auto_warm="SKIP"
fi

echo "results (median of ${BENCH_RUNS}, milliseconds):"
echo
printf '%-26s %12s %12s\n' "Op" "Cold (ms)" "Warm (ms)"
printf '%-26s %12s %12s\n' "--------------------------" "------------" "------------"
printf '%-26s %12s %12s\n' "whoami"               "${m_whoami_cold}" "${m_whoami_warm}"
printf '%-26s %12s %12s\n' "spawn (oath-admitted)" "${m_spawn_cold}"  "${m_spawn_warm}"
printf '%-26s %12s %12s\n' "delegate-spawn"        "${m_deleg_cold}"  "${m_deleg_warm}"
printf '%-26s %12s %12s\n' "audit --verify"        "${m_audit_cold}"  "${m_audit_warm}"
printf '%-26s %12s %12s\n' "reap --cascade (3-node)" "${m_cascade_cold}" "${m_cascade_warm}"
printf '%-26s %12s %12s\n' "auto (1 tick, quiet)"  "${m_auto_cold}"   "${m_auto_warm}"
echo
echo "note: COLD = fresh MONSTER_GUARD_HOME per run; WARM = repeated against a"
echo "      warm, initialized home. Heavy fat-station inference is NOT timed here"
echo "      (that is the demo's Gate A). The auto row times one autonomic tick"
echo "      reading a QUIET partyline (it HOLDs), so it is the loop's read+decide"
echo "      overhead only. Markdown row for the README:"
echo
echo "| whoami | ${m_whoami_cold} | ${m_whoami_warm} |"
echo "| spawn (oath-admitted) | ${m_spawn_cold} | ${m_spawn_warm} |"
echo "| delegate-spawn | ${m_deleg_cold} | ${m_deleg_warm} |"
